INSERT INTO assessment_submissions (user_id, type, total_score, max_score, category, category_percentage, dimension_scores, submitted_at) VALUES (62, 'pwb', 42, 108, 'Rendah', 39, '{\"self_acceptance\":{\"label\":\"Penerimaan Diri\",\"score\":15,\"max_score\":18,\"percentage\":83.33,\"category\":\"Tinggi\",\"feedback\":\"Anda menunjukkan kemampuan yang baik dalam menerima diri sendiri, baik kelebihan maupun kekurangan yang dimiliki. Anda juga cenderung mampu memandang pengalaman hidup sebagai bagian dari proses pembelajaran dan perkembangan diri. Pertahankan sikap positif ini sebagai bekal dalam menghadapi berbagai tantangan kehidupan.\"},\"positive_relations\":{\"label\":\"Hubungan Positif dengan Orang Lain\",\"score\":16,\"max_score\":18,\"percentage\":88.89,\"category\":\"Tinggi\",\"feedback\":\"Anda memiliki kemampuan yang baik dalam membangun hubungan yang hangat, saling percaya, dan saling mendukung dengan orang lain. Kemampuan ini merupakan salah satu faktor penting dalam menjaga kesejahteraan psikologis. Terus pertahankan komunikasi yang sehat dengan lingkungan sekitar.\"},\"autonomy\":{\"label\":\"Otonomi\",\"score\":4,\"max_score\":18,\"percentage\":22.22,\"category\":\"Rendah\",\"feedback\":\"Hasil menunjukkan bahwa Anda mungkin masih sering bergantung pada penilaian atau pendapat orang lain dalam mengambil keputusan. Cobalah melatih kepercayaan diri dan biasakan mengambil keputusan berdasarkan pertimbangan pribadi yang matang.\"},\"environmental_mastery\":{\"label\":\"Penguasaan Lingkungan\",\"score\":2,\"max_score\":18,\"percentage\":11.11,\"category\":\"Rendah\",\"feedback\":\"Anda mungkin sedang mengalami kesulitan dalam mengelola berbagai tuntutan kehidupan sehari-hari sehingga lebih mudah merasa tertekan. Cobalah membagi tugas menjadi langkah-langkah kecil, membuat jadwal yang teratur, dan meminta bantuan apabila diperlukan.\"},\"purpose_in_life\":{\"label\":\"Tujuan Hidup\",\"score\":4,\"max_score\":18,\"percentage\":22.22,\"category\":\"Rendah\",\"feedback\":\"Hasil menunjukkan bahwa Anda mungkin masih merasa bingung mengenai tujuan atau arah hidup yang ingin dicapai. Cobalah mulai menetapkan tujuan sederhana yang realistis dan sesuai dengan nilai-nilai yang Anda anggap penting.\"},\"personal_growth\":{\"label\":\"Pertumbuhan Pribadi\",\"score\":1,\"max_score\":18,\"percentage\":5.56,\"category\":\"Rendah\",\"feedback\":\"Anda mungkin sedang merasa kurang termotivasi untuk berkembang atau melakukan perubahan dalam hidup. Mulailah dengan menetapkan target kecil yang dapat dicapai secara bertahap agar proses pengembangan diri terasa lebih ringan dan bermakna.\"}}', '2026-07-13 16:07:09');
